import { readFile } from 'node:fs/promises';
import path from 'node:path';
import {
  ROOT_DIR,
  resolveRootPath,
  runGenerator,
  updateFileIfChanged,
} from './generator-utils.mjs';

const FOOTER_HTML_PATH = resolveRootPath('content/components/footer/footer.html');
const GENERATED_MODULE_PATH = resolveRootPath(
  'content/components/footer/footer-template.generated.js',
);

function buildGeneratedModule(footerHtml) {
  return `// Generated by scripts/sync-footer-template.mjs from content/components/footer/footer.html.
// Do not edit manually.

export const FOOTER_HTML = ${JSON.stringify(footerHtml)};
`;
}

async function main() {
  const footerHtml = await readFile(FOOTER_HTML_PATH, 'utf8');
  const generatedModule = buildGeneratedModule(footerHtml);

  const updated = await updateFileIfChanged(
    GENERATED_MODULE_PATH,
    generatedModule,
  );

  console.log(
    updated
      ? `Updated ${path.relative(ROOT_DIR, GENERATED_MODULE_PATH)}`
      : 'Footer template artifacts are already up to date.',
  );
}

await runGenerator(main);
